CREATE INDEX "claims_trusted_open_task_status_idx" ON "claims" USING btree ("user_id","stated_at" DESC NULLS LAST,"created_at" DESC NULLS LAST,"subject_node_id") WHERE "claims"."predicate" = 'HAS_TASK_STATUS' AND "claims"."status" = 'active' AND "claims"."scope" = 'personal' AND "claims"."asserted_by_kind" <> 'assistant_inferred' AND "claims"."object_value" IN ('pending', 'in_progress');--> statement-breakpoint
CREATE INDEX "claims_candidate_open_task_status_idx" ON "claims" USING btree ("user_id","stated_at" DESC NULLS LAST,"created_at" DESC NULLS LAST,"subject_node_id") WHERE "claims"."predicate" = 'HAS_TASK_STATUS' AND "claims"."status" = 'active' AND "claims"."scope" = 'personal' AND "claims"."asserted_by_kind" = 'assistant_inferred' AND "claims"."object_value" IN ('pending', 'in_progress');--> statement-breakpoint
CREATE INDEX "claims_task_metadata_lookup_idx" ON "claims" USING btree ("user_id","subject_node_id","predicate","stated_at" DESC NULLS LAST) WHERE "claims"."status" = 'active' AND "claims"."scope" = 'personal' AND "claims"."predicate" IN ('OWNED_BY', 'DUE_ON') AND "claims"."object_node_id" IS NOT NULL;